import{_ as e,o as a,c as o,d as i}from"./index.4ce7143c.js";const s={},c={class:"adp","data-respond-to-offset":"true"},t=i('<section class="breadcrumbs"><div class="breadcrumbs-overlay"></div><div class="breadcrumbs-wrapper"><div class="breadcrumb-items"><a href="/web/" class="breadcrumb">Home</a> <span class="divider"></span> <a href="/web/coffee" class="breadcrumb">All Coffee</a> <span class="divider"></span> <a href="/web/coffee/how-to-guides" class="breadcrumb">How-To Guides</a></div></div></section><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col-12"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-80 t-height-35 d-height-30"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_1700_JPEG/hero-desktop-30percent-3840x1152.069fe3c1.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_3400_JPEG/hero-desktop-30percent-3840x1152.d9f3f7ac.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_1699_JPEG/hero-desktop-30percent-3840x1152.6c37f870.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_3398_JPEG/hero-desktop-30percent-3840x1152.4379b65b.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_1399_JPEG/hero-desktop-30percent-3840x1152.7ffa5278.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_2798_JPEG/hero-desktop-30percent-3840x1152.b6e1d6c0.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_1199_JPEG/hero-desktop-30percent-3840x1152.a6f6ee61.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_2398_JPEG/hero-desktop-30percent-3840x1152.1432e6aa.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5545/image-thumb__5545__responsive_991_JPEG/hero-tablet-35percent-1982x694.d7e7fb6f.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5545/image-thumb__5545__responsive_1982_JPEG/hero-tablet-35percent-1982x694.d19e26eb.jpg 2x" data-alt="hero tablet 35percent 1982x694"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5544/image-thumb__5544__responsive_767_JPEG/hero-mobile-80percent-1534x1227.32c96156.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5544/image-thumb__5544__responsive_1534_JPEG/hero-mobile-80percent-1534x1227.e0dd565f.jpg 2x" data-alt="hero mobile 80percent 1534x1227"><img alt="hero desktop 30percent 3840x1152" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5544/image-thumb__5544__responsive_1_JPEG/hero-mobile-80percent-1534x1227.46c4bcef.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_1199_JPEG/hero-desktop-30percent-3840x1152.a6f6ee61.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5543/image-thumb__5543__responsive_2398_JPEG/hero-desktop-30percent-3840x1152.1432e6aa.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div><section class="article"><div class="section-inner"><div class="article-wrapper"><div class="article-body"><div class="article-overview-wrapper object-overview-wrapper"><div class="article-information object-information"><div class="article-name"><h1 class="heading">How to Make a Cappuccino</h1></div><div class="article-author"><div class="eyebrow"> By: Folgers (Folgerscoffee.com)</div></div><div class="article-description"></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>There\u2019s no need to leave your home to get that coffeehouse feel and flavor of a cappuccino. It\u2019s easy to make your favorite specialty coffee drinks using <strong>Folgers</strong><sup>\xAE</sup> coffee. If you&#39;re a coffee lover, you know that cappuccino is one of the most popular coffee drinks out there. It&#39;s a perfect balance of espresso, steamed milk, and frothy milk foam that creates a creamy and delicious flavor. But have you ever wondered how to make a perfect cappuccino? Look no further, because we have got you covered with this step-by-step guide!\xA0</p></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Directions</h2></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h4 class="align-left color-dark-red heading">These easy step-by-step instructions will help you make a delicious cappuccino right in your own kitchen:</h4></div></div></div></div></div><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Gather your ingredients</strong><br>To make a perfect cappuccino, you need three main ingredients: espresso/coffee, milk, and foam.\xA0\xA0</p><p><strong>Steam the milk</strong><br>Heat 1 cup of milk in a 2-quart saucepan over medium heat. Let the milk simmer until bubbles form around the edges, but don\u2019t boil the milk. Remove the pan from heat and set it on a flat surface.\xA0</p><p><strong>Whip the milk with an electric mixer</strong><br>Increase the speed as the milk begins to thicken. Continue mixing until you get the desired volume of froth. </p><p><strong>Make the coffee</strong><br>Measure 2 tablespoons of grounds for 5 to 6 oz of water. Try using <a href="/web/coffee/ground/black-silk"><strong>Folgers</strong> Black Silk</a> for an intense yet smooth flavor . You can brew the coffee in an automatic drip coffeemaker or a French press.</p><p><strong>Make the cappuccino</strong><br>A classic cappuccino calls for 1/3 espresso, 1/3 steamed milk, and 1/3 foam. You can mix it up by using 2 or 3 tablespoons of flavored syrups or even different kinds of milk, like chocolate or vanilla.\xA0</p><p><strong>Garnish and serve</strong><br>You can sprinkle some cocoa powder or cinnamon on top of the frothed milk for an extra touch of flavor. Then, serve your cappuccino immediately and enjoy!\xA0 </p></div></div></div></div></div></div><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-100 t-height-35 d-height-25"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1700_JPEG/Body-2-tab-desktop.5aa1b52e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_3400_JPEG/Body-2-tab-desktop.5856af10.jpg 2x" data-alt="Body 2 tab desktop"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1699_JPEG/Body-2-tab-desktop.db2ad4f3.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_3398_JPEG/Body-2-tab-desktop.0a0b7a59.jpg 2x" data-alt="Body 2 tab desktop"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1399_JPEG/Body-2-tab-desktop.a9706f8f.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_2798_JPEG/Body-2-tab-desktop.16d47466.jpg 2x" data-alt="Body 2 tab desktop"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1199_JPEG/Body-2-tab-desktop.1f7105fc.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_2398_JPEG/Body-2-tab-desktop.bdf93d06.jpg 2x" data-alt="Body 2 tab desktop"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_991_JPEG/Body-2-tab-desktop.6b70149e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1982_JPEG/Body-2-tab-desktop.0f57ba67.jpg 2x" data-alt="Body 2 tab desktop"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5547/image-thumb__5547__responsive_767_JPEG/Body-2.d0498786.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5547/image-thumb__5547__responsive_1534_JPEG/Body-2.f6d7345a.jpg 2x" data-alt="Body 2"><img alt="Body 2 tab desktop" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5547/image-thumb__5547__responsive_1_JPEG/Body-2.b27ad991.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_1199_JPEG/Body-2-tab-desktop.1f7105fc.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5867/image-thumb__5867__responsive_2398_JPEG/Body-2-tab-desktop.bdf93d06.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12 v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading">Bonus Tips For Making the Perfect Cappuccino</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><ul><li>For the best flavor potential of your coffee, begin by using a clean brewing device.\xA0 </li><li>Froth your milk to a velvety texture, not too hot or too cold. Milk used in cappuccinos should be approximately 145 \xB0F. Overheating the milk can give it a burnt taste and texture.\xA0 </li><li>Pour the steamed milk into the coffee first: hold the steamed milk pitcher at a slight angle and pour the milk in a circular motion to create a smooth, uniform texture. Then, spoon the frothed milk on top\xA0 </li><li>Add fun latte art. Use the milk foam to create a pattern or design on top of the cappuccino.\xA0 </li><li>Serve your cappuccino immediately for the best taste\xA0 </li><li>Add your favorite flavors to kick up your cappuccino. Some common flavors of cappuccino include vanilla, caramel, chocolate, and hazelnut, which can be added using flavored syrups or powders, or by adding a small amount of the flavoring to the milk before steaming it. Other popular additions to cappuccinos include cinnamon, nutmeg, and cocoa powder, which can be sprinkled on top of the foam.\xA0 </li></ul></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper bg-cream"><div class="container-full"><div class="row"><div class="col v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><span class="align-left eyebrow heading"></span></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h4 class="align-center color-black heading"> CAPPUCCINO</h4></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h3 class="align-center color-dark-red heading"> The classic Italian drink, which is made with espresso and steamed milk, pairs well with a variety of sweet treats like biscotti, tiramisu, and cannoli.</h3></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><p class="align-left heading"></p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12 v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Pairings</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>When it comes to cappuccino pairings, there are many delicious options to consider. The classic Italian drink, which is made with espresso and steamed milk, pairs well with a variety of sweet treats like biscotti, tiramisu, and cannoli. For a savory pairing, try serving your cappuccino alongside a breakfast sandwich or a quiche for a delicious brunch option. Another unique pairing to consider is cheese, such as Parmesan or Asiago, which complements the rich and creamy flavor of the cappuccino. Ultimately, the best cappuccino pairing is the one that you enjoy the most, so don&#39;t be afraid to experiment and try new combinations until you find your perfect match.</p></div></div></div></div></div></div><div class="col v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-100 t-height-35 d-height-25"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1700_JPEG/Body-3-tab-desktop.ecc95656.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_3400_JPEG/Body-3-tab-desktop.0c57470f.jpg 2x" data-alt="Body 3 tab desktop"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1699_JPEG/Body-3-tab-desktop.be6b2a5e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_3398_JPEG/Body-3-tab-desktop.e23148b6.jpg 2x" data-alt="Body 3 tab desktop"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1399_JPEG/Body-3-tab-desktop.59e705fe.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_2798_JPEG/Body-3-tab-desktop.0388fce7.jpg 2x" data-alt="Body 3 tab desktop"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1199_JPEG/Body-3-tab-desktop.c0776ace.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_2398_JPEG/Body-3-tab-desktop.c395798b.jpg 2x" data-alt="Body 3 tab desktop"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_991_JPEG/Body-3-tab-desktop.02b0dcee.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1982_JPEG/Body-3-tab-desktop.5188ea1d.jpg 2x" data-alt="Body 3 tab desktop"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5548/image-thumb__5548__responsive_767_JPEG/Body-3.497f2e3e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5548/image-thumb__5548__responsive_1534_JPEG/Body-3.77037491.jpg 2x" data-alt="Body 3"><img alt="Body 3 tab desktop" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5548/image-thumb__5548__responsive_1_JPEG/Body-3.6610949a.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_1199_JPEG/Body-3-tab-desktop.c0776ace.jpg 1x, https://www.folgerscoffee.com/folgers/articles/How%20To%20Make%20A%20Cappuccino/5868/image-thumb__5868__responsive_2398_JPEG/Body-3-tab-desktop.c395798b.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Frequently Asked Cappuccino Questions</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>How do you froth milk for a cappuccino?\xA0</strong><br>To froth milk for a cappuccino, you should use cold, fresh whole milk and steam it with an espresso machine&#39;s steam wand. The milk should be heated to around 140-150\xB0F while creating a microfoam texture.\xA0</p><p><strong>Can I use non-dairy milk for a cappuccino?</strong><br>Yes, you can use non-dairy milk like soy, almond, or oat milk for a cappuccino. However, the taste and texture may differ slightly from a traditional cappuccino made with cow&#39;s milk. \xA0</p><p><strong>How do I know if I made a good cappuccino?</strong><br>A good cappuccino should have a balance between espresso, steamed milk, and milk foam, a smooth and velvety texture, and a thick crema on top of the espresso. The taste should be rich and flavorful with a good balance of sweetness and bitterness.\xA0</p><p><strong>What is the origin of Cappuccino?</strong><br>The cappuccino is a coffee drink that originated in Italy in the early 20th century. It is believed to have been developed in the coffee shops of Trieste, Italy in the 1930s.\xA0 </p><p><strong>Do I need to use a specific type of milk?\xA0</strong><br>While cow&#39;s milk is the most commonly used type of milk for making cappuccinos, you can use any type of milk you prefer, including non-dairy milk such as almond, soy or oat milk.\xA0</p><p><strong>What is the ideal temperature for steaming milk?\xA0</strong><br>The ideal temperature for steaming milk for a cappuccino is between 140-150\xB0F. This will create a velvety texture without scalding the milk.\xA0</p><p><strong>How do I create latte art on my cappuccino?</strong>\xA0<br>To create latte art on your cappuccino, start by pouring the steamed milk into the espresso shot and then use a tool like a toothpick or a latte art pen to create your desired pattern.\xA0</p><p><strong>Can I use a French Press to make a cappuccino?</strong>\xA0<br>While a French Press is not the most common method for making a cappuccino, it is possible to use one. Start by brewing a strong batch of coffee, then froth and steam milk separately, and finally pour the steamed milk and foam over the coffee.\xA0</p><p><strong>Can I make a cappuccino without an espresso machine?\xA0</strong><br>Yes, it is possible to make a cappuccino without an espresso machine. You can use a stovetop espresso maker, French press, Moka pot, or drip machine to brew a strong coffee for a cappuccino.\xA0</p></div></div></div></div></div></div></div></div></div></div></div></div></div></section>',3),r=[t];function p(n,d){return a(),o("main",c,r)}var m=e(s,[["render",p]]);export{m as default};
